package com.conduit.nexus

import androidx.compose.runtime.*
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.chaquo.python.Python
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.File

class ConduitViewModel : ViewModel() {
    var chatMessages by mutableStateOf<List<Message>>(listOf(Message(0, "AI", "Hello! I am your AI File Manager.", true)))
    var sessions by mutableStateOf<List<Pair<String, String>>>(emptyList())
    var currentSessionId by mutableStateOf<String?>(null)
    var isAiThinking by mutableStateOf(false)
    var isDataLoading by mutableStateOf(false)
    var currentCwd by mutableStateOf("/storage/emulated/0")
    var stagedFiles by mutableStateOf<List<File>>(emptyList())
    var chatInput by mutableStateOf("")
    var editingMessageId by mutableStateOf<Long?>(null)

    private val python = Python.getInstance()
    private val executor = python.getModule("executor")

    init {
        refreshSessions()
        syncCwd()
    }

    fun refreshSessions() {
        viewModelScope.launch {
            isDataLoading = true
            sessions = SupabaseClient.fetchSessionsFromSupabase()
            isDataLoading = false
        }
    }

    fun loadSession(id: String) {
        viewModelScope.launch {
            isDataLoading = true
            currentSessionId = id
            chatMessages = SupabaseClient.fetchHistoryForSession(id)
            isDataLoading = false
        }
    }

    fun createNewChat() {
        viewModelScope.launch {
            isDataLoading = true
            val newId = SupabaseClient.createNewSessionInSupabase()
            if (newId != null) {
                currentSessionId = newId
                chatMessages = emptyList()
                refreshSessions()
            }
            isDataLoading = false
        }
    }

    fun deleteSession(id: String) {
        viewModelScope.launch {
            if (SupabaseClient.deleteSessionFromSupabase(id)) {
                if (currentSessionId == id) {
                    currentSessionId = null
                    chatMessages = listOf(Message(0, "AI", "Session deleted.", true))
                }
                refreshSessions()
            }
        }
    }

    fun sendMessage(displayAsSystem: Boolean = false) {
        val text = chatInput
        if (text.isBlank() && stagedFiles.isEmpty()) return

        val finalPrompt = if (stagedFiles.isNotEmpty()) {
            "[Attached Files: ${stagedFiles.joinToString { it.absolutePath }}]\n\n$text"
        } else text

        chatInput = ""
        stagedFiles = emptyList()

        viewModelScope.launch {
            isAiThinking = true

            if (editingMessageId != null) {
                val msgIndex = chatMessages.indexOfFirst { it.id == editingMessageId }
                if (msgIndex != -1 && currentSessionId != null) {
                    chatMessages = chatMessages.take(msgIndex)
                    SupabaseClient.truncateHistory(currentSessionId!!, text)
                }
                editingMessageId = null
            }

            if (currentSessionId == null) {
                val newId = SupabaseClient.createNewSessionInSupabase()
                currentSessionId = newId
                refreshSessions()
            }

            val userMsg = Message(System.currentTimeMillis(), "User", if (displayAsSystem) "[System Action]" else finalPrompt, false, isSystemAction = displayAsSystem)
            chatMessages = chatMessages + userMsg

            val aiResponse = SupabaseClient.callGeminiEdgeFunction(finalPrompt, currentSessionId)
            chatMessages = chatMessages + Message(System.currentTimeMillis() + 1, "AI", aiResponse, true)

            syncCwd()
            isAiThinking = false
        }
    }

    fun syncCwd() {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                val path = python.getModule("os").callAttr("getcwd").toString()
                withContext(Dispatchers.Main) { currentCwd = path }
            } catch (e: Exception) { }
        }
    }

    fun resetPython() {
        viewModelScope.launch(Dispatchers.IO) {
            executor.callAttr("reset_state")
            syncCwd()
        }
    }

    fun addStagedFile(file: File) { stagedFiles = stagedFiles + file }
    fun removeStagedFile(file: File) { stagedFiles = stagedFiles.filter { it != file } }
}

