                    query = searchQuery,
                    onQueryChange = { searchQuery = it },
                    onToggle = { isSearching = !isSearching },
                    onSearch = {
                        viewModel.explorerCategory = "Search Results"
                        viewModel.isScanningExplorer = true
                        scope.launch(Dispatchers.IO) {
                            val results = FileScanner.searchFilesNative(context, searchQuery)
                            withContext(Dispatchers.Main) {
                                viewModel.explorerFiles = results
                                viewModel.isScanningExplorer = false
                            }
                        }
                    }
                )
            }

            LazyColumn(modifier = Modifier.fillMaxSize()) {
                item { Spacer(modifier = Modifier.height(15.dp)) }

                // Storage Card
                item {
                    StorageUsageCard(
                        label = viewModel.storageLabel, 
                        percent = viewModel.storagePercent,
                        onClick = { openCategory("Internal Storage") }
                    )
                }

                item { Spacer(modifier = Modifier.height(25.dp)) }

                // Category Grid
                item {
                    CategoryGrid(onCatClick = { openCategory(it) })
                }

                item { Spacer(modifier = Modifier.height(30.dp)) }

                // Recent Files Section
                item {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Recent Files", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
                        Text(
                            text = "View All", 
                            color = Color(0xFF00E5FF), 
                            style = MaterialTheme.typography.labelLarge,
                            modifier = Modifier.clickable { openCategory("Recent Files") }
                        )
                    }
                    Spacer(modifier = Modifier.height(15.dp))
                }

                items(viewModel.dashboardRecentFiles) { file ->
                    FileRow(
                        file = file, 
                        isHighlighted = selectedFiles.contains(file),
                        onClick = {
                            if (selectedFiles.isNotEmpty()) {
                                viewModel.toggleSelection(file)
                            } else {
                            val f = java.io.File(file.path)
                                                if (f.isDirectory) {
                        viewModel.explorerCategory = "Internal Storage"
                        loadFolder(f.absolutePath)
