                                                        intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
                                                        context.startActivity(Intent.createChooser(intent, "Open with"))
                                                    } catch (e: Exception) { }
                                                }
                                            }
                                        },
                                        onLongClick = { viewModel.toggleSelection(file) }
